import{_ as e,o,c,e as t}from"./app-52052bff.js";const r="/assets/image-31d43ef3.png",s="/assets/image-1-e1fef346.png",d={},n=t('<p><img src="'+r+'" alt="Alt text"></p><h2 id="安装-启动-使用-ubuntu-22-04" tabindex="-1"><a class="header-anchor" href="#安装-启动-使用-ubuntu-22-04" aria-hidden="true">#</a> 安装 &amp; 启动 &amp; 使用（Ubuntu 22.04）</h2><p>卸载旧版本: <code>sudo apt-get remove docker docker-engine docker.io containerd</code></p><p>安装 docker : <code>sudo apt-get install docker-ce docker-ce-cli containerd.io docker-compose-plugin</code></p><p>启动 docker ：<code>sudo systemctl enable docker</code></p><p>运行 hello-world ：<code>sudo docker run hello-world</code></p><p>注意：需要配置镜像加速，提升拉取镜像的速度</p><h2 id="常用命令" tabindex="-1"><a class="header-anchor" href="#常用命令" aria-hidden="true">#</a> 常用命令</h2><ol><li>启动：<code>systemctl start docker</code></li><li>停止：<code>systemctl stop docker</code></li><li>重启：<code>systemctl restart docker</code></li><li>查看状态：<code>systemctl status docker</code></li><li>查看 docker 版本：<code>docker version</code></li><li>查看 docker 信息：<code>docker info</code></li><li>列出本机镜像：<code>docker images</code></li><li>下载镜像：<code>docker pull 镜像名称[:版本号]</code></li><li>删除镜像：<code>docker rmi 镜像名称/ID</code></li></ol><h2 id="容器" tabindex="-1"><a class="header-anchor" href="#容器" aria-hidden="true">#</a> 容器</h2><p><img src="'+s+`" alt="Alt text"></p><p><strong>启动容器</strong>: <code>docker run [OPTIONS] IMAGE [COMMAND] [ARG...]</code></p><ul><li>--name：为容器指定一个名称</li><li>-d：后台运行容器并返回容器ID，也即启动守护式容器</li><li>-e：为容器添加环境变量</li><li>-P：随机端口映射。将容器内暴露的所有端口映射到宿主机随机端口</li><li>-p：指定端口映射 <ul><li>-p hostPort:containerPort：端口映射，例如-p 8080:80</li><li>-p ip:hostPort:containerPort：配置监听地址，例如 -p 10.0.0.1:8080:80</li><li>-p ip::containerPort：随机分配端口，例如 -p 10.0.0.1::80</li><li>-p hostPort1:containerPort1 -p hostPort2:containerPort2：指定多个端口映射，例如-p 8080:80 -p 8888:3306</li></ul></li></ul><p><strong>列出正在运行的容器</strong>: <code>docker ps [OPTIONS]</code></p><ul><li>-a：列出当前所有正在运行的容器+历史上运行过的容器</li><li>-l：显示最近创建的容器</li><li>-n：显示最近n个创建的容器</li><li>-q：静默模式，只显示容器编号</li></ul><p><strong>启动已经停止的容器</strong>: <code>docker start 容器ID或容器名</code></p><p><strong>重启容器</strong>:<code>docker restart 容器ID或容器名</code></p><p><strong>停止容器</strong>: <code>docker stop 容器ID或容器名</code></p><p><strong>强制停止容器</strong>: <code>docker kill 容器ID或容器名</code></p><p><strong>删除容器</strong>: <code>docker rm 容器ID或容器名</code> 强制删除: <code>docker rm -f 容器ID或容器名</code></p><p><strong>查看容器日志</strong>：<code>docker logs 容器ID或容器名</code></p><p><strong>查看容器内运行的进程</strong>：<code>docker top 容器ID或容器名</code></p><p><strong>查看容器内部细节</strong>: <code>docker inspect 容器ID或容器名</code></p><p><strong>进入正在运行的容器</strong>: + <code>docker exec -it 容器ID bashShell</code></p><p><strong>重新进入</strong>: <code>docker attach 容器ID</code></p><p><strong>文件拷贝</strong>:</p><ul><li>容器内文件拷贝到宿主机：<code>docker cp 容器ID:容器内路径 目的主机路径</code></li><li>宿主机文件拷贝到容器中: <code>docker cp 主机路径 容器ID:容器内路径</code></li></ul><p><strong>导入和导出容器</strong></p><ul><li>export：导出容器的内容流作为一个tar归档文件（对应import命令）；</li><li>import：从tar包中的内容创建一个新的文件系统再导入为镜像（对应export命令）；</li></ul><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 导出</span>
<span class="token comment"># docker export 容器ID &gt; tar文件名</span>
<span class="token function">docker</span> <span class="token builtin class-name">export</span> abc <span class="token operator">&gt;</span> aaa.tar

<span class="token comment"># 导入</span>
<span class="token comment"># cat tar文件 | docker import - 自定义镜像用户/自定义镜像名:自定义镜像版本号</span>
<span class="token function">cat</span> aaa.tar <span class="token operator">|</span> <span class="token function">docker</span> <span class="token function">import</span> - test/mytest:1.0.1
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>将容器生成新镜像</strong>: <code>docker commit -m=&quot;提交的描述信息&quot; -a=&quot;作者&quot; 容器ID 要创建的目标镜像名:[tag]</code></p><h2 id="镜像" tabindex="-1"><a class="header-anchor" href="#镜像" aria-hidden="true">#</a> 镜像</h2><h2 id="dockerfile" tabindex="-1"><a class="header-anchor" href="#dockerfile" aria-hidden="true">#</a> Dockerfile</h2>`,33),a=[n];function i(l,p){return o(),c("div",null,a)}const u=e(d,[["render",i],["__file","index.html.vue"]]);export{u as default};
